      return;
    }
    let stats = null;
    try {
      stats = fs.lstatSync(absolutePath);
    } catch (_error) {
      stats = null;
    }
    if (!stats) {
      touched.add(entry.path);
      return;
    }

    if (entry.type === 'symlink') {
      if (!stats.isSymbolicLink()) {
        touched.add(entry.path);
        return;
      }
